sql:
SELECT species_name
FROM vegetation
WHERE vegetation_cover > 75.0;

SELECT site_name
FROM sites
ORDER BY site_name;

SELECT AVG(vegetation_cover) AS overall_avg_vegetation_cover
FROM vegetation v
JOIN samples s ON v.sample_id = s.sample_id;

SELECT file_name
FROM photo_files
WHERE file_type = 'PNG';

SELECT species_name
FROM vegetation
ORDER BY vegetation_cover DESC;
